import{_ as a,o as r,c as o,a2 as e}from"./chunks/framework.Bjylvv1V.js";const b=JSON.parse('{"title":"민원 접수/처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/complaint.md","filePath":"guide/scenarios/complaint.md","lastUpdated":null}'),l={name:"guide/scenarios/complaint.md"};function n(s,t,i,d,h,c){return r(),o("div",null,[...t[0]||(t[0]=[e(`<h1 id="민원-접수-처리" tabindex="-1">민원 접수/처리 <a class="header-anchor" href="#민원-접수-처리" aria-label="Permalink to &quot;민원 접수/처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 10분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 수시 (민원 발생 시)</p></blockquote><p>세대 또는 입주자의 시설 고장, 불편 사항 등 민원을 접수하고 작업을 지시·처리·완료 보고하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><h3 id="사전-설정-최초-1회" tabindex="-1">사전 설정 (최초 1회) <a class="header-anchor" href="#사전-설정-최초-1회" aria-label="Permalink to &quot;사전 설정 (최초 1회)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 작업코드등록   (10분) → 자재/기기/시설물/기타 대분류 설정</span></span>
<span class="line"><span>2. 기기등록       (10분) → 전기·기계·조경 등 관리 기기 등록</span></span>
<span class="line"><span>3. 제품등록       (10분) → 자재 부품·규격·단가·적정재고량 등록</span></span>
<span class="line"><span>4. 거래처등록     (5분)  → 자재 구매처 등록</span></span>
<span class="line"><span>5. 민원코드등록   (10분) → 민원 대분류/소분류 코드 설정</span></span></code></pre></div><h3 id="일상-업무-건당" tabindex="-1">일상 업무 (건당) <a class="header-anchor" href="#일상-업무-건당" aria-label="Permalink to &quot;일상 업무 (건당)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 민원 접수      (3분)  → 동호수·접수내용·민원코드 입력</span></span>
<span class="line"><span>2. 작업 처리      (5분)  → 작업내역 입력, 자재 출고 시 출고등록</span></span>
<span class="line"><span>3. 완료 보고      (2분)  → 처리결과 저장</span></span>
<span class="line"><span>4. 해피콜 서비스  (선택) → 만족도 확인</span></span></code></pre></div><h3 id="자재-관리-수시" tabindex="-1">자재 관리 (수시) <a class="header-anchor" href="#자재-관리-수시" aria-label="Permalink to &quot;자재 관리 (수시)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 입고등록   → 거래처·부품·수량·단가 입력</span></span>
<span class="line"><span>2. 출고등록   → 사용부서·부품·수량 입력</span></span>
<span class="line"><span>3. 이월작업   → 월말 결산 전 처리</span></span></code></pre></div><hr><h2 id="사전-설정-최초-1회-1" tabindex="-1">사전 설정 (최초 1회) <a class="header-anchor" href="#사전-설정-최초-1회-1" aria-label="Permalink to &quot;사전 설정 (최초 1회)&quot;">​</a></h2><p>처음 시스템을 사용할 때 한 번만 설정합니다. 이후에는 변경이 있을 때만 수정합니다.</p><h3 id="작업코드등록" tabindex="-1">작업코드등록 <a class="header-anchor" href="#작업코드등록" aria-label="Permalink to &quot;작업코드등록&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 작업코드등록 (JOBM1100)</p></blockquote><p>민원 작업의 분류 체계를 설정합니다.</p><table tabindex="0"><thead><tr><th>대분류</th><th>예시 소분류</th></tr></thead><tbody><tr><td>자재</td><td>배관부품, 전기자재, 소모품</td></tr><tr><td>기기</td><td>엘리베이터, 보일러, 소방설비</td></tr><tr><td>시설물</td><td>공용복도, 주차장, 조경</td></tr><tr><td>기타</td><td>민원상담, 행정업무</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">작업코드 수정 불가</p><p>저장된 작업코드는 <strong>수정이 불가</strong>합니다. 코드명만 변경할 수 있으므로, 등록 전에 분류 체계를 신중하게 설계하세요.</p></div><h3 id="기기등록" tabindex="-1">기기등록 <a class="header-anchor" href="#기기등록" aria-label="Permalink to &quot;기기등록&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 기기등록 (JOBM1100)</p></blockquote><p>단지 내 관리 대상 기기를 등록합니다.</p><ul><li>전기설비: 수변전설비, 비상발전기, 소방전기</li><li>기계설비: 급수펌프, 오수펌프, 보일러</li><li>조경: 자동급수, 분수대</li></ul><h3 id="제품등록" tabindex="-1">제품등록 <a class="header-anchor" href="#제품등록" aria-label="Permalink to &quot;제품등록&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 제품등록 (JOBM1100)</p></blockquote><p>민원 처리에 사용하는 자재 부품을 등록합니다.</p><table tabindex="0"><thead><tr><th>입력 항목</th><th>설명</th></tr></thead><tbody><tr><td>품명</td><td>부품 이름</td></tr><tr><td>규격</td><td>크기·형번 등</td></tr><tr><td>단가</td><td>구매 단가</td></tr><tr><td>적정재고량</td><td>재고 부족 알림 기준 수량</td></tr></tbody></table><h3 id="거래처등록" tabindex="-1">거래처등록 <a class="header-anchor" href="#거래처등록" aria-label="Permalink to &quot;거래처등록&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 거래처등록 (JOBM1100)</p></blockquote><p>자재 납품 업체 정보를 등록합니다. 입고 처리 시 사용됩니다.</p><h3 id="민원코드등록" tabindex="-1">민원코드등록 <a class="header-anchor" href="#민원코드등록" aria-label="Permalink to &quot;민원코드등록&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 민원코드등록 (JOBM1200)</p></blockquote><p>민원 종류를 대분류/소분류로 구분하여 등록합니다.</p><table tabindex="0"><thead><tr><th>대분류 예시</th><th>소분류 예시</th></tr></thead><tbody><tr><td>전기</td><td>세대 내 누전, 공용 조명 불량</td></tr><tr><td>수도</td><td>누수, 수압 불량</td></tr><tr><td>난방/온수</td><td>난방 불량, 온수 미공급</td></tr><tr><td>주차</td><td>장애물, 불법 주차</td></tr><tr><td>소음</td><td>층간소음, 공사 소음</td></tr></tbody></table><hr><h2 id="_1단계-민원-접수-3분" tabindex="-1">1단계: 민원 접수 (3분) <a class="header-anchor" href="#_1단계-민원-접수-3분" aria-label="Permalink to &quot;1단계: 민원 접수 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 세대민원접수및작업 (JOBM1200)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>세대민원접수및작업 화면 진입</li><li><strong>행추가</strong> 클릭</li><li>다음 항목을 입력:</li></ol><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>접수부서</td><td>담당 부서 선택</td></tr><tr><td>접수자</td><td>접수 직원 선택</td></tr><tr><td>동/호수</td><td>민원 세대 선택</td></tr><tr><td>접수일시</td><td>자동 입력 (수정 가능)</td></tr><tr><td>민원코드</td><td>대분류→소분류 순서로 선택</td></tr><tr><td>접수내용</td><td>민원 내용 상세 입력</td></tr></tbody></table><ol start="4"><li><strong>저장</strong> 클릭</li><li>필요 시 <strong>민원접수증</strong> 출력 (입주자 교부용)</li></ol><div class="tip custom-block"><p class="custom-block-title">민원접수증 출력</p><p>접수 후 입주자에게 접수증을 제공하면 처리 상황 문의 시 접수번호로 조회할 수 있습니다.</p></div><hr><h2 id="_2단계-작업-처리-5분" tabindex="-1">2단계: 작업 처리 (5분) <a class="header-anchor" href="#_2단계-작업-처리-5분" aria-label="Permalink to &quot;2단계: 작업 처리 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 세대민원접수및작업 (JOBM1200)</p></blockquote><p>접수된 민원을 선택하여 작업 내역을 입력합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>접수된 민원 선택</li><li><strong>작업지시서</strong> 출력 (선택) → 담당 기사에게 교부</li><li>작업 완료 후 <strong>작업내역 탭</strong> 입력: <ul><li>작업일시</li><li>담당자</li><li>작업내용 (수행한 조치 상세 기술)</li><li>사용 자재 (출고 연계)</li></ul></li><li>자재를 사용한 경우 → <strong>출고등록</strong> 연계 처리 (아래 참고)</li><li><strong>저장</strong></li></ol><h3 id="출고등록-자재-사용-시" tabindex="-1">출고등록 (자재 사용 시) <a class="header-anchor" href="#출고등록-자재-사용-시" aria-label="Permalink to &quot;출고등록 (자재 사용 시)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 출고등록 (JOBM1300)</p></blockquote><p>민원 처리 중 창고 자재를 사용한 경우 출고를 등록합니다.</p><ol><li>출고등록 화면 진입</li><li><strong>사용부서</strong> 선택</li><li>사용 <strong>부품 및 수량</strong> 입력</li><li><strong>저장</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">출고 수량 초과 불가</p><p>현재 입고 수량을 초과하여 출고할 수 없습니다. 재고가 부족한 경우 먼저 입고등록을 처리하세요.</p></div><hr><h2 id="_3단계-완료-보고-2분" tabindex="-1">3단계: 완료 보고 (2분) <a class="header-anchor" href="#_3단계-완료-보고-2분" aria-label="Permalink to &quot;3단계: 완료 보고 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 세대민원접수및작업 (JOBM1200)</p></blockquote><p>작업 완료 후 처리 결과를 저장하고 민원을 종결합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>해당 민원 선택</li><li><strong>처리상태</strong>를 &#39;완료&#39;로 변경</li><li>처리 결과 내용 최종 확인</li><li><strong>저장</strong></li><li><strong>세대민원처리대장</strong> 출력 (월별 보고용)</li></ol><hr><h2 id="_4단계-해피콜-서비스-선택" tabindex="-1">4단계: 해피콜 서비스 (선택) <a class="header-anchor" href="#_4단계-해피콜-서비스-선택" aria-label="Permalink to &quot;4단계: 해피콜 서비스 (선택)&quot;">​</a></h2><p>민원 처리 후 세대 입주자에게 연락하여 처리 만족도를 확인합니다.</p><ul><li>전화 또는 문자로 처리 결과 안내</li><li>불만족 시 재처리 접수</li><li>만족도 점수는 시스템에 기록 가능</li></ul><hr><h2 id="자재-관리" tabindex="-1">자재 관리 <a class="header-anchor" href="#자재-관리" aria-label="Permalink to &quot;자재 관리&quot;">​</a></h2><h3 id="입고등록" tabindex="-1">입고등록 <a class="header-anchor" href="#입고등록" aria-label="Permalink to &quot;입고등록&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 입고등록 (JOBM1300)</p></blockquote><p>자재를 구매하여 창고에 입고할 때 등록합니다.</p><ol><li>거래처 선택</li><li>입고 부품·수량·단가 입력</li><li>저장 → 재고 자동 증가</li></ol><h3 id="이월작업" tabindex="-1">이월작업 <a class="header-anchor" href="#이월작업" aria-label="Permalink to &quot;이월작업&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 이월작업 (JOBM1300)</p></blockquote><p>월말 결산 전, 미완료 작업을 다음 달로 이월합니다.</p><div class="danger custom-block"><p class="custom-block-title">이월작업 시점</p><p>이월작업은 <strong>월말 결산 전</strong>에 반드시 처리해야 합니다. 결산 후에는 이월 처리가 제한될 수 있습니다.</p></div><h3 id="기기보수" tabindex="-1">기기보수 <a class="header-anchor" href="#기기보수" aria-label="Permalink to &quot;기기보수&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/manage.html">민원관리</a> &gt; 기기보수 (JOBM1300)</p></blockquote><p>단지 내 기기의 보수 이력을 기록합니다.</p><table tabindex="0"><thead><tr><th>입력 항목</th><th>설명</th></tr></thead><tbody><tr><td>기기</td><td>보수 대상 기기 선택</td></tr><tr><td>보수일자</td><td>실제 보수한 날짜</td></tr><tr><td>고장원인</td><td>고장 내용 상세 기술</td></tr><tr><td>처리내용</td><td>수행한 보수 작업 내용</td></tr><tr><td>담당자</td><td>처리 기사</td></tr></tbody></table><hr><h2 id="민원-현황-조회" tabindex="-1">민원 현황 조회 <a class="header-anchor" href="#민원-현황-조회" aria-label="Permalink to &quot;민원 현황 조회&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 민원 &gt; <a href="/jobm/inquiry.html">민원조회</a> (JOBM1200)</p></blockquote><h3 id="주요-조회-기능" tabindex="-1">주요 조회 기능 <a class="header-anchor" href="#주요-조회-기능" aria-label="Permalink to &quot;주요 조회 기능&quot;">​</a></h3><ul><li><strong>기간별 민원 목록</strong>: 접수일 기준 조회</li><li><strong>처리 상태별 조회</strong>: 접수 중 / 처리 중 / 완료 / 보류</li><li><strong>세대별 민원 이력</strong>: 특정 동·호수의 민원 내역 확인</li><li><strong>담당자별 처리 현황</strong>: 직원별 처리 건수 파악</li></ul><h3 id="출력-서류" tabindex="-1">출력 서류 <a class="header-anchor" href="#출력-서류" aria-label="Permalink to &quot;출력 서류&quot;">​</a></h3><table tabindex="0"><thead><tr><th>서류</th><th>용도</th></tr></thead><tbody><tr><td>민원접수증</td><td>입주자 교부</td></tr><tr><td>작업지시서</td><td>담당 기사 교부</td></tr><tr><td>세대민원처리대장</td><td>월별 업무 보고</td></tr></tbody></table><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="민원코드가-목록에-없어요" tabindex="-1">민원코드가 목록에 없어요 <a class="header-anchor" href="#민원코드가-목록에-없어요" aria-label="Permalink to &quot;민원코드가 목록에 없어요&quot;">​</a></h3><p><strong>원인</strong>: 민원코드가 등록되지 않았습니다. <strong>해결</strong>: 민원코드등록(JOBM1200) 화면에서 해당 분류를 추가하세요. 대분류를 먼저 등록한 후 소분류를 추가해야 합니다.</p><h3 id="출고-처리-시-재고-부족-오류가-나요" tabindex="-1">출고 처리 시 재고 부족 오류가 나요 <a class="header-anchor" href="#출고-처리-시-재고-부족-오류가-나요" aria-label="Permalink to &quot;출고 처리 시 재고 부족 오류가 나요&quot;">​</a></h3><p><strong>원인</strong>: 등록된 재고 수량보다 많은 양을 출고하려 하는 경우 <strong>해결</strong>: 입고등록(JOBM1300)에서 재고를 먼저 추가하거나, 출고 수량을 실제 재고 범위 내로 수정하세요.</p><h3 id="작업코드를-잘못-등록했어요" tabindex="-1">작업코드를 잘못 등록했어요 <a class="header-anchor" href="#작업코드를-잘못-등록했어요" aria-label="Permalink to &quot;작업코드를 잘못 등록했어요&quot;">​</a></h3><p><strong>원인</strong>: 작업코드는 저장 후 수정이 불가합니다. <strong>해결</strong>: 코드명만 수정할 수 있습니다. 분류 구조 자체가 잘못된 경우 새 코드를 추가하고 기존 코드는 미사용 상태로 관리하세요.</p><h3 id="이월작업을-깜빡하고-결산을-했어요" tabindex="-1">이월작업을 깜빡하고 결산을 했어요 <a class="header-anchor" href="#이월작업을-깜빡하고-결산을-했어요" aria-label="Permalink to &quot;이월작업을 깜빡하고 결산을 했어요&quot;">​</a></h3><p><strong>원인</strong>: 월말 결산 전 이월 처리를 하지 않은 경우 <strong>해결</strong>: 관리자에게 문의하여 결산 해제 후 이월 처리를 진행하세요. 다음 달부터는 <strong>결산 전 이월작업</strong>을 체크리스트에 포함하세요.</p><h3 id="민원-처리-이력이-조회되지-않아요" tabindex="-1">민원 처리 이력이 조회되지 않아요 <a class="header-anchor" href="#민원-처리-이력이-조회되지-않아요" aria-label="Permalink to &quot;민원 처리 이력이 조회되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 조회 기간 또는 상태 필터 설정 오류 <strong>해결</strong>: <a href="/jobm/inquiry.html">민원조회</a>에서 기간을 넓게 설정하고 처리 상태를 &#39;전체&#39;로 변경하여 다시 조회하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/jobm/manage.html">민원관리</a> - 민원 접수·작업 처리·자재 관리</li><li><a href="/jobm/inquiry.html">민원조회</a> - 민원 현황 및 이력 조회</li><li><a href="/occp/inquiry.html">입주자 조회</a> - 세대 입주자 정보 확인</li></ul>`,98)])])}const g=a(l,[["render",n]]);export{b as __pageData,g as default};
